var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"나리!! 옥상에서 구경만 하지 말고 나리 친구들 좀 보내 줘! 어서!","JPN":"旦那！！　屋上で見てないでお仲間を送ってくれ！　早く！","ENG":"Hey!! Don’t just stand there and watch! Send your friends down! Come on!","TWN":"姊！你別只是在屋頂上看熱鬧，快派你的朋友來啊！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"그 망할 년이 자꾸 어디선가 튀어나와서 뒤통수를 친다고! 이러다 우리 애들 다 죽겠어!","JPN":"あのクソ女がしきりにどこかから不意打ちしてきやがる！　このままじゃうちの奴ら全部死ぬぞ！","ENG":"That damn girl is going to reappear out of nowhere and get us all! At this rate we’re all die!","TWN":"那該死的女人一直不知道從哪裡冒出來，殺我們個措手不及！再這樣下去我們會全軍覆沒的!"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"기다려. 지금 부른 참이니까.","JPN":"待っていろ。今呼んだ。","ENG":"Hold on. I’m calling for someone.","TWN":"等等，我正打算要派人過去。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤……! 설마 우릴 미끼로 쓴 건 아니겠지?","JPN":"へ、へへ……！　まさか俺らをエサにしたんじゃないだろうな？","ENG":"Hey, hey...! Don’t tell me you’re using us as bait?","TWN":"嘿嘿嘿……！你該不會是拿我們當誘餌吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"그러다 나리도 죽어. 나리도 죽일 거라고, 응?","JPN":"それじゃ旦那も死ぬよ。俺が殺すから、な？","ENG":"You’ll die too, you know! You hear me?","TWN":"這樣姊也會沒命的！因為我會殺掉姊！知道嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"나한테 한눈 팔 시간이 있던가? 허세 부리지 말고 네 할일이나 잘 챙겨.","JPN":"私を見ている暇があるのか？　強がってないで自分の仕事にでも集中しろ。","ENG":"Is this really the proper time for this? Shouldn’t you be focusing on something else? Stop wasting time and take care of business.","TWN":"你有時間分心跟我說這些嗎？少在那邊虛張聲勢，把你該做的事做好！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래. 한눈 팔면 이렇게 뒤통수에 총구가 닿거든.","JPN":"そうそう。よそ見してるとこうやって頭に銃口が来ちゃうものね。","ENG":"My words exactly. If you focus on the wrong things even for a moment, you could end up just like this.","TWN":"沒錯，分心的話，就會像這樣被人拿槍指著後腦勺。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"방금 그 목소리 뭐야, 나리? 그 년이야?","JPN":"今の声はなんだ、旦那？　あの女か？","ENG":"Hey what was that noise just now? Was it the girl?","TWN":"剛剛那是什麼聲音？是那女的嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"설마 나리한테 갔어? 그 년은 우리 아빠를 죽인 년이야! 손대면 가만 안 둬!!","JPN":"まさか旦那のところに行ったのか？　あの女は俺のおやじを殺した女だ！　手を出したら許さねえぞ！","ENG":"No way, she got you too? She killed my father! I won’t let her get away with this!!","TWN":"她在姊那裡嗎？那女的是我的殺父仇人！我要親手解決她！不准你碰她！！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"이봐! 야!! 야 이 개──!!","JPN":"オイ！　こら！！　このクソ――！！","ENG":"Hey! Hey!! You fxx─!!","TWN":"喂！喂！你這該死的臭──！！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"나를 어떻게 찾았지?","JPN":"どうやって私を見つけた？","ENG":"How did you find me?","TWN":"你是怎麼找到我的？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"파레마에서 봤을 때부터 줄곧 마음에 걸렸거든.","JPN":"パレマで見かけた時からずっとひっかかってたの。","ENG":"You know, something’s been on my mind ever since I saw you in Parema.","TWN":"自從在波雷馬見到你後，我就一直放在心上。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"자크가 죽었다고 저렇게 미쳐 날뛸 부하들은 그 날 대부분 처리했어.","JPN":"ジャックが死んだからってあんな風に暴れそうな部下は、あの日ほとんど始末したから。","ENG":"I've dealt with most of Jacques's men who could go mad for his death that day.","TWN":"札克死掉那天，我明明就已經把大部分的手下都處理掉了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러면 누군가 저들을 선동했다는 거겠지. 약물로 정신을 흐트러뜨린 채로.","JPN":"そうだとしたら誰かがあいつらを煽ったってこと。薬で精神を乱してね。","ENG":"Someone must have made them behave that way. After drugging them.","TWN":"也就是說一定是有人煽動其餘的人，用藥物控制他們。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"파레마에서 저격할 때도 날 저격한 사람이 너였지?","JPN":"パレマで狙撃した時に私を狙ったのも君だったのね？","ENG":"You were the one who shot at me in Parema, right?","TWN":"在波雷馬的時候，狙擊我的人就是你吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"누구 명령으로 이러는지 대답해, 꼬마.","JPN":"誰の命令で動いてるのか答えなさい、ガキ。","ENG":"Tell me. Who gave you the order, kid?","TWN":"是誰指使你的？回答我，小鬼！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"명령?","JPN":"命令？","ENG":"Order?","TWN":"指使？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"다른 사람도 아닌 너한테 그런 말을 들을 줄은 몰랐어. 웃을 수 있었다면 웃었을 텐데.","JPN":"他の誰でもなく、あなたにそう言われるとは思わなかった。笑うことができたら笑ってた。","ENG":"That’s not something I expected to hear from you. If it were possible for me to laugh I would right now.","TWN":"沒想到會從你嘴裡聽到這番話，要是我笑得出來，肯定會哈哈大笑。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"무슨 뜻이지?","JPN":"どういう意味？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"너랑 같이 있던 꼬맹이처럼 소년병이라도 되는 줄 알았나? 아니면 그런 척 하는 건가?","JPN":"あなたと一緒にいたチビのような少年兵だと思ったか？　それともそんな振りをしてるのか？","ENG":"Do you really think you are just a child soldier like that kid you’re with? Or are you just pretending right now?","TWN":"你以為我會和你身邊那個小鬼一樣，成為童軍嗎？還是你在裝蒜？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"어느 쪽이나 뻔뻔스럽기 짝이 없군. 가증스러운 개자식 같으니라고.","JPN":"どっちにしろ図々しいな。この憎たらしいクソ野郎が。","ENG":"Either way you look at it, it’s pathetic. How despicable.","TWN":"真是有夠厚顏無恥，令人可噁心的傢伙！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……반군이 보낸 암살자인가 했더니, 단순한 망상가였나?","JPN":"……反乱軍から送られた暗殺者かと思えば、単なる空想家だったの？","ENG":"...I thought you were an assassin sent by the rebels, but maybe you’re just insane?","TWN":"……我原本猜你是叛軍派來的殺手，結果你只是單純有妄想症喔？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"반군들에게 투항하라고 전해. 더 이상 날뛰게 두면 너부터 이 자리에서 죽이겠어.","JPN":"反乱軍に降伏するように伝えて。これ以上暴れたらこの場で君から殺すよ。","ENG":"Tell the rebels to stand down. If you let them do anything reckless, I’ll kill you right now.","TWN":"叫叛軍投降，再敢輕舉妄動，我就先殺了你！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"해볼 테면 해보시지.","JPN":"やれるものならやってみろ。","ENG":"Go ahead, do it.","TWN":"有本事你試試看！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"하지만 이번에는 그리 쉽지 않을 거다.","JPN":"でも今度はうまく行かないはずだ。","ENG":"But it won’t be as easy as you think this time.","TWN":"但這次可不會那麼容易！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"모르스!!","JPN":"モールス！！","ENG":"Mors!!","TWN":"莫爾斯！！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"뭐야, 저건……?","JPN":"何、あれ……？","ENG":"What on earth is that?","TWN":"那是什麼……？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"언제나 한 발 늦는군. 어디 있다 이제 온 거지?","JPN":"いつも一足遅いな。なんで今になって来たんだ？","ENG":"You’re always a step late. Where have you been?","TWN":"你總是慢一步，怎麼現在才來？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"익숙한 기척이 느껴졌다. 하지만 곧 종적을 감추더군.","JPN":"見慣れた気配を感じたのだ。だがすぐ姿を消した。","ENG":"I had a familiar feeling. Yet soon disappeared.","TWN":"有一種熟悉的感覺，不過很快就會銷聲匿跡。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"기계……? 아니, 사람인가……?","JPN":"機械……？いや、人……？","ENG":"Is that a machine...? No, a person...?","TWN":"是機器……？還是人……？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……네가 지목한 여인이로군.","JPN":"……貴様が目を付けた女であるな。","ENG":"...The woman of which you spoke I see.","TWN":"……這就是你說的那個女人嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"여전히 역병의 악취가 풍기지 않는다. 그대의 말을 신뢰할 가치가 존재하는가.","JPN":"相変わらず疫病の悪臭はしておらぬ。そなたの言葉を信ずる価値があるのだろうか。","ENG":"And yet, I can’t feel the stench of the plague. Is there worth in trusting you?","TWN":"完全沒有散發出瘟疫的惡臭，你的話值得相信嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"학회로부터 얻은 정보고, 프리드웬이 끼어든 정황도 있어.","JPN":"学会からの情報で、プリドウェンが割り込んだ状況もある。","ENG":"It was information received from the Society, there’s also circumstantial evidence that Prydwen is involved.","TWN":"這是來自學會的情報，而且還有普利多溫的介入，"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"내 말을 믿을 가치는 없더라도 확인해 볼 만한 가치는 있지.","JPN":"私の言葉に信じる価値がないとしても確認してみる価値はあるだろう。","ENG":"Even if you don’t trust me, it’s worth checking out.","TWN":"就算我的話不值得相信，但還是值得確認看看吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……그렇군. 휘말리지 않도록 물러서라.","JPN":"……さようか。巻き込まれないよう、下がっていろ。","ENG":"...Very well. Stand back, so you avoid the coming storm.","TWN":"……好吧，那你離遠點，否則會被殃及到。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"들어라, 여인이여.","JPN":"聞け、女よ。","ENG":"Heed my words, woman.","TWN":"女人，你聽著，"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나는, 너의 사악한 본색을 확인하고자 여기 당도하였도다.","JPN":"我は、貴様の邪悪な本性を確認すべくここへ来たれり。","ENG":"I have arrived to confirm your evil nature.","TWN":"我來此的目的是要確認你邪惡的真面目。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"사악하다니……. 당신도 저 망상가랑 같은 부류인가 보네.","JPN":"邪悪って……あなたもそっちの空想家と同じ部類のようね。","ENG":"What do you mean evil... I guess you’re on the same team as that crazy girl.","TWN":"邪惡什麼……你也跟那個人一樣有妄想症嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"혹시나 하는 마음에 묻겠는데, 그 확인이라는 건 어떻게 할 작정이지?","JPN":"もしかしてと思って聞くけど、その確認ってのはどうやってするつもり？","ENG":"So just to be clear...how do you plan to confirm it?","TWN":"我只是好奇問一下，你是要如何確認？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"피할 수 없는 죽음 앞에서는 제 아무리 교활한 허물도 벗겨지는 법.","JPN":"避けられない死の前ではいくら狡猾な皮であっても脱がざるを得まい。","ENG":"In the face of inevitable death, one’s true nature is revealed.","TWN":"當面臨到死亡時，再怎麼詭詐的偽裝也都會露出破綻。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 도시는 오늘, 너의 형장이 되리니.","JPN":"この街は今日、貴様の刑場となろう。","ENG":"On this day, this city shall become the place of your execution.","TWN":"今天這座城市，就是你的刑場。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"의연히 안식을 받아들여라.","JPN":"毅然と安息をを受け入れろ。","ENG":"Receive this rest honorably.","TWN":"進入安息吧！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……<color=#ffd34c>마에스트로.</color>","JPN":"……<color=#ffd34c>マエストロ</color>。","ENG":"…<color=#ffd34c>Maestra.</color>","TWN":"……<color=#ffd34c>指揮家。</color>"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};